	// Returns a snapshot of the page as a string (MHTML). Experimental.
	CaptureSnapshot(context.Context, *CaptureSnapshotRequest) (*CaptureSnapshotResponse, error)
	// Print page as PDF.
	PrintToPDF(context.Context, *PrintToPDFRequest) (*PrintToPDFResponse, error)
	// Returns present frame tree structure.
	GetFrameTree(context.Context, *GetFrameTreeRequest) (*GetFrameTreeResponse, error)
	// Returns metrics relating to the layouting of the page.
	GetLayoutMetrics(context.Context, *GetLayoutMetricsRequest) (*GetLayoutMetricsResponse, error)
	// Sets given markup as the document's HTML.
	SetDocumentContent(context.Context, *SetDocumentContentRequest) (*SetDocumentContentResponse, error)
	// Brings page to front (activates tab).
	BringToFront(context.Context, *BringToFrontRequest) (*BringToFrontResponse, error)
	// Tries to close page, running its beforeunload hooks, if any.
	Close(context.Context, *CloseRequest) (*CloseResponse, error)
