	AddScriptToEvaluateOnNewDocument(context.Context, *AddScriptToEvaluateOnNewDocumentRequest) (*AddScriptToEvaluateOnNewDocumentResponse, error)
	// Removes given script from the list.
	RemoveScriptToEvaluateOnNewDocument(context.Context, *RemoveScriptToEvaluateOnNewDocumentRequest) (*RemoveScriptToEvaluateOnNewDocumentResponse, error)
	// Enable Chrome's experimental ad filter on all sites.
	SetAdBlockingEnabled(context.Context, *SetAdBlockingEnabledRequest) (*SetAdBlockingEnabledResponse, error)
	// Overrides the values of device screen dimensions.
	SetBypassCSP(context.Context, *SetBypassCSPRequest) (*SetBypassCSPResponse, error)
	// Controls whether page will emit lifecycle events.
	SetLifecycleEventsEnabled(context.Context, *SetLifecycleEventsEnabledRequest) (*SetLifecycleEventsEnabledResponse, error)
	// Accepts or dismisses a JavaScript initiated dialog.
	HandleJavaScriptDialog(context.Context, *HandleJavaScriptDialogRequest) (*HandleJavaScriptDialogResponse, error)
	// Returns content of the given resource (experimental).
	GetResourceContent(context.Context, *GetResourceContentRequest) (*GetResourceContentResponse, error)
	// Returns present frame / resource tree structure (experimental).
	GetResourceTree(context.Context, *GetResourceTreeRequest) (*GetResourceTreeResponse, error)
	// Searches for given string in resource content (experimental).
	SearchInResource(context.Context, *SearchInResourceRequest) (*SearchInResourceResponse, error)
	// Creates an isolated world for the given frame.
	CreateIsolatedWorld(context.Context, *CreateIsolatedWorldRequest) (*CreateIsolatedWorldResponse, error)
	// Starts sending each frame using the screencastFrame event (experimental).
	StartScreencast(context.Context, *StartScreencastRequest) (*StartScreencastResponse, error)
	// Stops sending each frame in the screencastFrame (experimental).
	StopScreencast(context.Context, *StopScreencastRequest) (*StopScreencastResponse, error)
	// Acknowledges that a screencast frame has been received (experimental).
	ScreencastFrameAck(context.Context, *ScreencastFrameAckRequest) (*ScreencastFrameAckResponse, error)
	// Set generic font families (experimental).
	SetFontFamilies(context.Context, *SetFontFamiliesRequest) (*SetFontFamiliesResponse, error)
	// Set default font sizes (experimental).
	SetFontSizes(context.Context, *SetFontSizesRequest) (*SetFontSizesResponse, error)
	// Intercept file chooser requests and transfer control to protocol clients (experimental).
	SetInterceptFileChooserDialog(context.Context, *SetInterceptFileChooserDialogRequest) (*SetInterceptFileChooserDialogResponse, error)
	// Crashes renderer (experimental).
	Crash(context.Context, *CrashRequest) (*CrashResponse, error)
	// Generates a report for testing (experimental).
	GenerateTestReport(context.Context, *GenerateTestReportRequest) (*GenerateTestReportResponse, error)
	// Pauses page execution (experimental).
	WaitForDebugger(context.Context, *WaitForDebuggerRequest) (*WaitForDebuggerResponse, error)
	// Sets the web lifecycle state of the page (experimental).
	SetWebLifecycleState(context.Context, *SetWebLifecycleStateRequest) (*SetWebLifecycleStateResponse, error)
	// Returns the list of errors for the page's installability (experimental).
	GetInstallabilityErrors(context.Context, *GetInstallabilityErrorsRequest) (*GetInstallabilityErrorsResponse, error)
	// Returns the web app manifest for the page (experimental).
	GetAppManifest(context.Context, *GetAppManifestRequest) (*GetAppManifestResponse, error)
	// Returns the unique (dedicated) app id for the page (experimental).
	GetAppId(context.Context, *GetAppIdRequest) (*GetAppIdResponse, error)
	// Returns permissions policy state for the page (experimental).
	GetPermissionsPolicyState(context.Context, *GetPermissionsPolicyStateRequest) (*GetPermissionsPolicyStateResponse, error)
	// Returns origin trials for the frame (experimental).
	GetOriginTrials(context.Context, *GetOriginTrialsRequest) (*GetOriginTrialsResponse, error)
	// Forces compilation cache to be generated (experimental).
	ProduceCompilationCache(context.Context, *ProduceCompilationCacheRequest) (*ProduceCompilationCacheResponse, error)
	// Seeds compilation cache for a given URL (experimental).
	AddCompilationCache(context.Context, *AddCompilationCacheRequest) (*AddCompilationCacheResponse, error)
	// Clears seeded compilation cache (experimental).
	ClearCompilationCache(context.Context, *ClearCompilationCacheRequest) (*ClearCompilationCacheResponse, error)
	// Sets whether prerendering is allowed (experimental).
	SetPrerenderingAllowed(context.Context, *SetPrerenderingAllowedRequest) (*SetPrerenderingAllowedResponse, error)
